// @ts-nocheck
import React, { useCallback, useEffect, useState } from 'react';
import ReactFlow, {
  Background,
  Controls,
  Handle,
  MiniMap,
  Position,
  applyNodeChanges,
  applyEdgeChanges,
} from 'reactflow';
import dagre from 'dagre';
import { LayoutGrid, Save, AlertTriangle, Loader2 } from 'lucide-react';
import { api } from '../../lib/api';
import { notify } from '../../lib/notify';
import 'reactflow/dist/style.css';

function TableNode({ data }: { data: any }) {
  return (
    <div className="bg-nv-panel text-nv-text border-2 border-nv-border rounded shadow-md min-w-[200px] text-xs relative">
      <Handle type="target" position={Position.Left} className="!w-2.5 !h-2.5 !bg-sky-500 !border-sky-300" />
      <div className="px-2 py-1 bg-nv-accent text-white font-semibold rounded-t flex items-center gap-1">
        <svg width="12" height="12" viewBox="0 0 24 24" fill="currentColor"><rect x="3" y="4" width="18" height="16" rx="1" /></svg>
        {data.label}
      </div>
      <div className="py-0.5">
        {(data.columns ?? []).slice(0, 12).map((col: any) => (
          <div key={col.name} className="px-2 py-0.5 flex items-center gap-1.5 font-mono text-2xs border-b border-nv-borderLight last:border-0">
            <span className="w-3 text-center">
              {col.isPrimaryKey && <span className="text-yellow-500">🔑</span>}
              {col.isForeignKey && !col.isPrimaryKey && <span className="text-sky-400">🔗</span>}
            </span>
            <span className="flex-1 truncate">{col.name}</span>
            <span className="text-nv-textMuted text-2xs">{col.type}</span>
          </div>
        ))}
        {(data.columns?.length ?? 0) > 12 && (
          <div className="px-2 py-0.5 text-2xs text-nv-textMuted">+ {data.columns.length - 12} more</div>
        )}
      </div>
      <Handle type="source" position={Position.Right} className="!w-2.5 !h-2.5 !bg-sky-500 !border-sky-300" />
    </div>
  );
}

const nodeTypes = { tableNode: TableNode };

const EDGE_OPTS = {
  type: 'smoothstep',
  animated: false,
  markerEnd: { type: 'arrowclosed', color: '#38bdf8', width: 18, height: 18 },
  style: { stroke: '#38bdf8', strokeWidth: 2 },
};

function layoutEr(nodes: any[], edges: any[]) {
  const g = new dagre.graphlib.Graph();
  g.setDefaultEdgeLabel(() => ({}));
  g.setGraph({ rankdir: 'LR', nodesep: 80, ranksep: 140 });
  nodes.forEach((n) => {
    g.setNode(n.id, {
      width: 220,
      height: 40 + ((n.data?.columns?.length ?? 3) * 18),
    });
  });
  edges.forEach((e) => g.setEdge(e.source, e.target));
  dagre.layout(g);
  return nodes.map((n) => {
    const pos = g.node(n.id);
    return { ...n, position: { x: pos.x - 110, y: pos.y - 20 } };
  });
}

function normalizeEdges(edges: any[]) {
  return (edges ?? []).map((e, i) => ({
    id: e.id ?? `er-edge-${i}`,
    source: e.source,
    target: e.target,
    label: e.label,
    ...EDGE_OPTS,
  }));
}

export function ErDiagramPanel({ connectionId, database }: { connectionId: string; database: string }) {
  const [nodes, setNodes] = useState<any[]>([]);
  const [edges, setEdges] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    setLoading(true);
    api.erGet(connectionId, database)
      .then(({ nodes: n, edges: ed }) => {
        const rfNodes = (n ?? []).map((node: any) => ({
          ...node,
          type: 'tableNode',
          position: node.position ?? { x: 0, y: 0 },
        }));
        setNodes(rfNodes);
        setEdges(normalizeEdges(ed));
      })
      .catch(console.error)
      .finally(() => setLoading(false));
  }, [connectionId, database]);

  const onNodesChange = useCallback((changes) => setNodes((nds) => applyNodeChanges(changes, nds)), []);
  const onEdgesChange = useCallback((changes) => setEdges((eds) => applyEdgeChanges(changes, eds)), []);

  const autoLayout = () => setNodes((nds) => layoutEr(nds, edges));

  const savePositions = async () => {
    const positions: Record<string, { x: number; y: number }> = {};
    nodes.forEach((n) => { positions[n.id] = n.position; });
    await api.erPositions(connectionId, database, positions);
    notify('Positions saved', 'ER Diagram');
  };

  if (loading) {
    return (
      <div className="p-4 text-nv-textMuted text-xs flex gap-1 items-center">
        <Loader2 size={12} className="animate-spin" /> Loading ER diagram…
      </div>
    );
  }

  const largeSchema = nodes.length > 60;

  return (
    <div className="h-full relative flex flex-col">
      {largeSchema && (
        <div className="text-xs px-3 py-1.5 bg-amber-950/40 border-b border-amber-800/50 text-amber-200 flex items-center gap-1">
          <AlertTriangle size={11} /> Large schema ({nodes.length} tables) — rendering may be slow.
        </div>
      )}
      <div className="flex-1 relative min-h-[320px]">
        <div className="absolute top-2 right-2 z-10 flex gap-2">
          <button type="button" onClick={autoLayout} className="nv-btn"><LayoutGrid size={11} /> Auto Layout</button>
          <button type="button" onClick={savePositions} className="nv-btn-primary"><Save size={11} /> Save Positions</button>
        </div>
        <ReactFlow
          nodes={nodes}
          edges={edges}
          onNodesChange={onNodesChange}
          onEdgesChange={onEdgesChange}
          nodeTypes={nodeTypes}
          fitView
          className="bg-nv-bg"
          defaultEdgeOptions={EDGE_OPTS}
          proOptions={{ hideAttribution: true }}
        >
          <Background gap={16} color="#334155" />
          <Controls showInteractive={false} />
          <MiniMap nodeColor="#1976d2" maskColor="rgba(0,0,0,0.12)" />
        </ReactFlow>
      </div>
    </div>
  );
}
